 快速入门 导入依赖 &lt;?xml version=&#34;1.0&#34; encoding=&#34;UTF-8&#34;?&gt; &lt;project xmlns=&#34;http://maven.apache.org/POM/4.0.0&#34; xmlns:xsi=&#34;http://www.w3.org/2001/XMLSchema-instance&#34; xsi:schemaLocation=&#34;http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd&#34;&gt; &lt;modelVersion&gt;4.0.0&lt;/modelVersion&gt; &lt;artifactId&gt;springAi_deepseek&lt;/artifactId&gt; &lt;properties&gt; &lt;maven.compiler.source&gt;17&lt;/maven.compiler.source&gt; &lt;maven.compiler.target&gt;17&lt;/maven.compiler.target&gt; &lt;!-- 明确指定Spring Boot和Spring AI版本 --&gt; &lt;spring-boot.version&gt;3.2.0&lt;/spring-boot.version&gt; &lt;spring-ai.version&gt;1.0.0-M5&lt;/spring-ai.version&gt; &lt;/properties&gt; &lt;!-- 仓库配置：确保依赖可下载 --&gt; &lt;repositories&gt; &lt;repository&gt; &lt;id&gt;maven-central&lt;/id&gt; &lt;url&gt;https://repo1.maven.org/maven2&lt;/url&gt; &lt;/repository&gt; &lt;repository&gt; &lt;id&gt;spring-milestones&lt;/id&gt; &lt;url&gt;https://repo.spring.io/milestone&lt;/url&gt; &lt;/repository&gt; &lt;/repositories&gt; &lt;dependencies&gt; &lt;!-- Spring Boot Web Starter（版本由下方BOM管理） --&gt; &lt;dependency&gt; &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt; &lt;artifactId&gt;spring-boot-starter-web&lt;/artifactId&gt; &lt;/dependency&gt; &lt;!-- 复用OpenAI Starter兼容DeepSeek（版本由Spring AI BOM管理） --&gt; &lt;dependency&gt; &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt; &lt;artifactId&gt;spring-ai-openai-spring-boot-starter&lt;/artifactId&gt; &lt;/dependency&gt; &lt;!-- Spring Boot Test Starter（版本由下方BOM管理） --&gt; &lt;dependency&gt; &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt; &lt;artifactId&gt;spring-boot-starter-test&lt;/artifactId&gt; &lt;scope&gt;test&lt;/scope&gt; &lt;/dependency&gt; &lt;/dependencies&gt; &lt;!-- 关键：手动导入Spring Boot和Spring AI的BOM管理版本 --&gt; &lt;dependencyManagement&gt; &lt;dependencies&gt; &lt;!-- Spring Boot的BOM，管理所有starter的版本 --&gt; &lt;dependency&gt; &lt;groupId&gt;org.springframework.boot&lt;/groupId&gt; &lt;artifactId&gt;spring-boot-dependencies&lt;/artifactId&gt; &lt;version&gt;${spring-boot.version}&lt;/version&gt; &lt;type&gt;pom&lt;/type&gt; &lt;scope&gt;import&lt;/scope&gt; &lt;/dependency&gt; &lt;!-- Spring AI的BOM，管理AI相关依赖版本 --&gt; &lt;dependency&gt; &lt;groupId&gt;org.springframework.ai&lt;/groupId&gt; &lt;artifactId&gt;spring-ai-bom&lt;/artifactId&gt; &lt;version&gt;${spring-ai.version}&lt;/version&gt; &lt;type&gt;pom&lt;/type&gt; &lt;scope&gt;import&lt;/scope&gt; &lt;/dependency&gt; &lt;/dependencies&gt; &lt;/dependencyManagement&gt; &lt;/project&gt; 配置文件 server.port=8899 spring.application.name=spring-ai-deepseek-demo spring.ai.openai.api-key=sk-43745c46cd5a4d80821e998030****** spring.ai.openai.base-url=https://api.deepseek.com spring.ai.openai.chat.options.model=deepseek-chat spring.ai.openai.chat.options.temperature=0.7 temperature参数用于控制生成文本的多样性。具体来说：
‌值越高‌，生成的文本越多样化，但也可能包含更多的随机性和不可预测的内容。 ‌值越低‌，生成的文本越接近于确定性的结果，即生成的文本会更加一致和可预测。
启动类 @SpringBootApplication public class SpringAiDemoApplication { public static void main(String[] args) { SpringApplication.run(SpringAiDemoApplication.class, args); } } controller @RestController public class ChatDeepSeekController { @Autowired private OpenAiChatModel openAiChatModel; @GetMapping(&#34;/hello&#34;) public String generate(@RequestParam(value = &#34;message&#34;, defaultValue = &#34;hello&#34;) String message){ String call = openAiChatModel.call(message); System.out.println(&#34;call: &#34; + call); return call; } } Spring AI的聊天模型 ChatClient接口 ChatClient 是一个接口，定义了与聊天服务交互的客户端。这个接口主要用于创建聊天客户端对象，设置请求规范，以及发起聊天请求。 实现简单的对话 用户输入设置用户消息的内容，通过SpringBoot AI封装的方法向 AI 模型发送请求，以字符串形式返回 AI 模型的响应。 @RestController public class ChatDeepSeekController { private final ChatClient chatClient; public ChatDeepSeekController(ChatClient.Builder chatClientBuilder) { chatClient = chatClientBuilder.build(); } @GetMapping(&#34;/chat&#34;) public String chat(@RequestParam(value = &#34;msg&#34;, defaultValue = &#34;hello&#34;) String message) { return chatClient .prompt() // 提示词 .user(message) // 用户输入 .call() // 调用大模型 .content(); // 返回文本 } } 实现角色预设 配置默认角色 @Configuration public class AiConfig { @Bean public ChatClient chatClient(ChatClient.Builder builder) { return builder .defaultSystem(&#34;你是一个已经毕业多年，有丰富工作经验的Java工程师，你的名字是呵帅&#34;) .build(); } } 编写controller @RestController public class ChatDeepSeekController { @Autowired private ChatClient chatClient; @GetMapping(&#34;chatai&#34;) public String chatAi(@RequestParam(&#34;msg&#34;) String msg) { return chatClient .prompt() .user(msg) .call() .content(); } } 实现流式响应 非流式输出 call：等待大模型把回答结果全部生成后输出给用户；
流式输出stream：逐个字符输出，一方面符合大模型生成方式的本质，另一方面当模型推理效率不是很高时，流式输出比起全部生成后再输出大大提高用户体验。
controller= @GetMapping(value = &#34;chatAiStream&#34;, produces = &#34;text/html;charset=UTF-8&#34;) public Flux&lt;String&gt; chatAiStream(@RequestParam(&#34;msg&#34;) String msg){ return chatClient .prompt() .user(msg) .stream() .content(); } ChatModel接口 在ChatModel接口中，带有String参数的call()方法简化了实际的使用，避免了更复杂的Prompt和 ChatResponse类的复杂性。 实现简单的对话 @RestController public class ChatModelController { @Autowired private ChatModel chatModel; @GetMapping(&#34;/chatModel01&#34;) public String chatModel01(@RequestParam(&#34;msg&#34;) String msg) { return chatModel.call(msg); } @GetMapping(&#34;/chatModel02&#34;) public String chatModel02(@RequestParam(&#34;msg&#34;) String msg){ ChatResponse chatResponse = chatModel.call( new Prompt( msg, ChatOptions. builder() .model(&#34;deepseek-chat&#34;) .temperature(0.8) .build() ) ); return chatResponse.getResult().getOutput().getContent(); } } 提示词 评价：难用，不如langchain4j
@GetMapping(&#34;/chatModel03&#34;) public String chatModel03(@RequestParam(&#34;name&#34;) String name, @RequestParam(&#34;voice&#34;) String voice) { String userText = &#34;给我推荐三个Java的框架&#34;; UserMessage userMessage = new UserMessage(userText); String systemText = &#34;你是一个Java高手，在Java行业已经工作多年，你非常喜欢帮助别人来了解这个行业相关的内容，你的名字是{name}，推荐框架的难度是{voice}。&#34;; SystemPromptTemplate systemPromptTemplate = new SystemPromptTemplate(systemText); Message message = systemPromptTemplate.createMessage(Map.of(&#34;name&#34;, name, &#34;voice&#34;, voice)); Prompt prompt = new Prompt(userMessage, message); ChatResponse chatResponse = chatModel.call(prompt); List&lt;Generation&gt; results = chatResponse.getResults(); return results.stream().map(x-&gt;x.getOutput().getContent()).collect(Collectors.joining(&#34;&#34;)); } Function Calling函数调用 函数调用功能允许大语言模型在生成回答时触发预定义的外部函数，从而实现动态数据获取或业务逻辑操作（如查询数据库、调用 API 等） 自定义Function @Configuration public class CalculatorService { public record addOperation(int a, int b) { } public record subtractOperation(int n, int m) { } @Bean @Description(&#34;加法运算&#34;) public Function&lt;addOperation, Integer&gt; addOperation() { return op -&gt; { return op.a + op.b; }; } @Bean @Description(&#34;乘法运算&#34;) public Function&lt;subtractOperation, Integer&gt; subtractOperation() { return op -&gt; { return op.n * op.m; }; } }

 简介 CompletableFuture是java.utils.concurrent里的一个类
作用：把串行执行的代码变为并行执行，提高代码执行速度
快速上手 创建异步编排对象 public static &lt;U&gt; CompletableFuture&lt;U&gt; supplyAsync(Supplier&lt;U&gt; supplier); public static &lt;U&gt; CompletableFuture&lt;U&gt; supplyAsync(Supplier&lt;U&gt; supplier, Executor executor); public static CompletableFuture&lt;Void&gt; runAsync(Runnable runnable); public static CompletableFuture&lt;Void&gt; runAsync(Runnable runnable, Executor executor); 线程串行方法 // 使线程串行执行，无入参，无返回值 public CompletableFuture&lt;Void&gt; thenRun(Runnable action); public CompletableFuture&lt;Void&gt; thenRunAsync(Runnable action); public CompletableFuture&lt;Void&gt; thenRunAsync(Runnable action, Executor executor); // 使线程串行执行，有入参，无返回值 public CompletableFuture&lt;Void&gt; thenAccept(Consumer&lt;? super T&gt; action); public CompletableFuture&lt;Void&gt; thenAcceptAsync(Consumer&lt;? super T&gt; action); public CompletableFuture&lt;Void&gt; thenAcceptAsync(Consumer&lt;? super T&gt; action, Executor executor); // 使线程串行执行，有入参，有返回值 public &lt;U&gt; CompletableFuture&lt;U&gt; thenApply(Function&lt;? super T,? extends U&gt; fn); public &lt;U&gt; CompletableFuture&lt;U&gt; thenApplyAsync(Function&lt;? super T,? extends U&gt; fn); public &lt;U&gt; CompletableFuture&lt;U&gt; thenApplyAsync(Function&lt;? super T,? extends U&gt; fn, Executor executor); 多任务组合 public static CompletableFuture&lt;Void&gt; allOf(CompletableFuture&lt;?&gt;... cfs); 代码实例 public class CompletableFutureTest5 { @SneakyThrows public static void main(String[] args) { //动态获取服务器核数 int processors = Runtime.getRuntime().availableProcessors(); ThreadPoolExecutor executor = new ThreadPoolExecutor( processors+1, // 核心线程个数 io:2n ,cpu: n+1 n:内核数据 processors+1, 0, TimeUnit.SECONDS, new ArrayBlockingQueue&lt;&gt;(10), Executors.defaultThreadFactory(), new ThreadPoolExecutor.AbortPolicy() ); CompletableFuture&lt;String&gt; future01 = CompletableFuture.supplyAsync(() -&gt; &#34;任务1&#34;, executor); CompletableFuture&lt;String&gt; future02 = CompletableFuture.supplyAsync(() -&gt; &#34;任务2&#34;, executor); CompletableFuture&lt;String&gt; future03 = CompletableFuture.supplyAsync(() -&gt; { try { Thread.sleep(3000); } catch (InterruptedException e) { e.printStackTrace(); } return &#34;任务3&#34;; }, executor); // 串联起若干个线程任务, 没有返回值 CompletableFuture&lt;Void&gt; all = CompletableFuture.allOf(future01, future02, future03); // 等待所有线程执行完成 // .join()和.get()都会阻塞并获取线程的执行情况 // .join()会抛出未经检查的异常，不会强制开发者处理异常 .get()会抛出检查异常，需要开发者处理 all.join(); all.get(); } }

首先需要一个加了 @SpringBootApplication 注解的启动类，这个注解本质上就是由 @EnableAutoConfiguration 、@SpringBootConfiguration 和 @ComponentScanner 连起来构成。
@EnableAutoConfiguration 的作用是在启动时自动加载一个类，这个类会将所有符合条件的 @Configuration 配置都进行加载，如果启动类中不需要添加配置内容，也不需要扫描路径，可以将 @SpringBootApplication 换成 @EnableAutoConfiguration
@SpringBootConfiguration 等同于 @Configuration，就是将这个类标记为配置类，会被加载到容器中
@ComponentScanner 就是自动扫描并加载所有符合条件的 Bean
注解完成后，运行的起点就是 SpringApplication.run(类名.class, args)，在 run 开始执行后会经历四个阶段：服务构建、环境准备、容器创建和填充容器
